#include <evmone_precompiles/modexp.hpp>
#include <gtest/gtest.h>
#include <array>

#include <test/utils/utils.hpp>
using namespace evmone::test;

TEST(evmmax, modexp)
{
    {
        evmc::bytes res;
        res.resize(1025);
        EXPECT_FALSE(evmone::crypto::modexp(
            ""_hex,
            evmc::bytes{0x3},
            ""_hex,
            res.data()));
    }
}
